:root {
    /* Color system */
    --color-primary-red: #D41414;
    --color-primary-green: #0F6B3A;
    --color-primary-blue: #003399;
    --color-secondary-silver: #C0C0C0;
    --color-accent-gold: #FFD54A;

    --color-neutral-000: #FFFFFF;
    --color-neutral-050: #F5F5F5;
    --color-neutral-100: #DDDDDD;
    --color-neutral-800: #444444;

    --color-semantic-success: #0F6B3A;
    --color-semantic-error: #D41414;
    --color-semantic-warning: #FFC107;
    --color-semantic-info: #1976D2;

    /* Typography */
    --font-heading: "Playfair Display", Georgia, serif;
    --font-body: "Libre Baskerville", "Times New Roman", serif;
    --font-code: "Source Code Pro", monospace;

    --font-size-h1: 32px;
    --font-size-h2: 26px;
    --font-size-h3: 20px;
    --font-size-body: 16px;
    --font-size-small: 13px;

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.75;

    /* Spacing scale (multiples of 8px) */
    --spacing-1: 4px;
    --spacing-2: 8px;
    --spacing-3: 16px;
    --spacing-4: 24px;
    --spacing-5: 32px;
    --spacing-6: 48px;
    --spacing-7: 64px;
}

/* Base layout */

*,
*::before,
*::after {
    box-sizing: border-box;
}

html {
    font-size: 100%;
}

body.museum-site {
    margin: 0;
    padding: 0;
    background-color: var(--color-neutral-050);
    color: var(--color-neutral-800);
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-relaxed);
}

.site-frame {
    min-height: 100vh;
    display: flex;
    flex-direction: column;
}

.container {
    max-width: 1120px;
    margin: 0 auto;
    padding: 0 var(--spacing-4);
}

a {
    color: var(--color-primary-green);
    text-decoration: none;
}

a:hover,
a:focus {
    text-decoration: underline;
}

img {
    max-width: 100%;
    height: auto;
    display: block;
}

.visually-hidden {
    position: absolute;
    width: 1px;
    height: 1px;
    padding: 0;
    margin: -1px;
    overflow: hidden;
    clip: rect(0, 0, 0, 0);
    border: 0;
}

/* Header */

.site-header {
    background-color: var(--color-neutral-000);
    color: var(--color-neutral-800);
    border-bottom: 1px solid var(--color-neutral-100);
}

.header-top-stripe {
    height: 6px;
    background-color: var(--color-primary-red);
}

.header-main {
    display: flex;
    align-items: flex-start;
    padding-top: var(--spacing-5);
    padding-bottom: var(--spacing-3);
}

.brand {
    display: flex;
    align-items: center;
    gap: var(--spacing-3);
    text-decoration: none;
    color: inherit;
}

.brand-mark {
    width: 76px;
    height: 76px;
    border-radius: 4px;
    border: 2px solid var(--color-primary-green);
    display: flex;
    align-items: center;
    justify-content: center;
    background-color: var(--color-neutral-000);
}

.brand-mark-text {
    font-family: var(--font-heading);
    font-size: 28px;
    line-height: var(--line-height-tight);
    color: var(--color-primary-green);
    font-weight: 700;
}

.brand-text {
    display: flex;
    flex-direction: column;
}

.brand-title {
    font-family: var(--font-heading);
    font-size: 22px;
    line-height: var(--line-height-tight);
    letter-spacing: 0.03em;
    text-transform: uppercase;
    color: var(--color-primary-red);
    margin-bottom: 4px;
}

.brand-subtitle {
    font-size: 14px;
    line-height: var(--line-height-normal);
    color: var(--color-neutral-800);
}

.header-utilities {
    margin-left: auto;
    text-align: right;
    font-size: var(--font-size-small);
}

.header-utilities-top {
    display: flex;
    align-items: center;
    justify-content: flex-end;
    gap: var(--spacing-2);
    margin-bottom: var(--spacing-2);
}

.utility-label {
    color: var(--color-neutral-800);
}

.utility-divider {
    color: var(--color-neutral-100);
}

.lang-pill {
    display: inline-block;
    padding: 2px 8px;
    min-width: 24px;
    text-align: center;
    background-color: var(--color-primary-blue);
    color: var(--color-neutral-000);
    font-size: 11px;
    text-transform: lowercase;
}

.lang-pill--active {
    font-weight: 700;
}

.header-search {
    margin-top: var(--spacing-2);
}

.header-search input[type="search"] {
    width: 260px;
    max-width: 100%;
    padding: 6px 8px;
    border: 1px solid var(--color-neutral-100);
    font-family: var(--font-body);
    font-size: 14px;
    line-height: var(--line-height-normal);
    color: var(--color-neutral-800);
}

.header-search input[type="search"]::placeholder {
    color: #999999;
}

.header-divider {
    border-top: 1px solid var(--color-neutral-100);
}

/* Primary navigation */

.primary-nav {
    background-color: var(--color-neutral-000);
}

.primary-menu {
    list-style: none;
    margin: 0;
    padding: var(--spacing-2) 0 var(--spacing-3);
    display: flex;
    flex-wrap: wrap;
    gap: var(--spacing-3);
}

.primary-menu-item {
    margin: 0;
}

.primary-link {
    font-family: var(--font-body);
    font-size: 14px;
    text-transform: none;
    color: var(--color-primary-red);
    text-decoration: none;
    padding-bottom: 4px;
    border-bottom: 2px solid transparent;
}

.primary-link:hover,
.primary-link:focus {
    text-decoration: none;
    border-bottom-color: var(--color-primary-red);
}

.primary-link--active {
    font-weight: 700;
    border-bottom-color: var(--color-primary-red);
}

/* Main content */

.site-content {
    flex: 1 0 auto;
}

.site-content .container {
    padding-top: var(--spacing-5);
    padding-bottom: var(--spacing-6);
}

.content-card {
    background-color: var(--color-neutral-000);
    border: 1px solid var(--color-neutral-100);
    border-radius: 3px;
    padding: var(--spacing-5);
    min-height: 220px;
}

/* Headings inside content cards (style reference for pages) */

.content-card h1 {
    font-family: var(--font-heading);
    font-size: var(--font-size-h1);
    line-height: var(--line-height-tight);
    color: var(--color-primary-red);
    margin-top: 0;
    margin-bottom: var(--spacing-3);
}

.content-card h2 {
    font-family: var(--font-heading);
    font-size: var(--font-size-h2);
    line-height: var(--line-height-tight);
    color: var(--color-primary-red);
    margin-top: var(--spacing-5);
    margin-bottom: var(--spacing-3);
}

.content-card p {
    margin-top: 0;
    margin-bottom: var(--spacing-3);
}

.content-card a {
    color: var(--color-primary-green);
    font-weight: 700;
}

/* Footer */

.site-footer {
    background-color: var(--color-neutral-050);
    color: var(--color-neutral-800);
    font-size: var(--font-size-small);
}

.footer-divider {
    border-top: 1px solid var(--color-neutral-100);
}

.footer-inner {
    padding-top: var(--spacing-4);
    padding-bottom: var(--spacing-5);
}

.footer-nav {
    margin-bottom: var(--spacing-2);
}

.footer-menu {
    list-style: none;
    margin: 0;
    padding: 0;
    display: flex;
    flex-wrap: wrap;
    gap: var(--spacing-3);
}

.footer-menu-item a {
    color: var(--color-primary-green);
    text-decoration: none;
}

.footer-menu-item a:hover,
.footer-menu-item a:focus {
    text-decoration: underline;
}

.footer-copy {
    margin: 0;
    color: #777777;
}

/* Code elements (for future use in articles/resources) */

code,
pre {
    font-family: var(--font-code);
}

/* Responsive adjustments */

@media (max-width: 768px) {
    .header-main {
        flex-direction: column;
        align-items: flex-start;
    }

    .header-utilities {
        margin-left: 0;
        margin-top: var(--spacing-3);
        text-align: left;
        width: 100%;
    }

    .header-utilities-top {
        justify-content: flex-start;
    }

    .header-search input[type="search"] {
        width: 100%;
    }

    .primary-menu {
        gap: var(--spacing-2);
    }

    .content-card {
        padding: var(--spacing-4);
    }
}

@media (max-width: 480px) {
    .brand {
        flex-direction: row;
        align-items: center;
    }

    .brand-mark {
        width: 64px;
        height: 64px;
    }

    .brand-title {
        font-size: 18px;
    }

    .brand-subtitle {
        font-size: 12px;
    }

    .primary-menu {
        flex-direction: column;
        align-items: flex-start;
    }
}
